mapper.update:
UPDATE user
SET bonusQuota = CASE
        WHEN COALESCE(dailyQuota, 0) >= #{cost}
            THEN COALESCE(bonusQuota, 0)
        ELSE COALESCE(bonusQuota, 0) - (#{cost} - COALESCE(dailyQuota, 0))
    END,
    dailyQuota = CASE
        WHEN COALESCE(dailyQuota, 0) >= #{cost}
            THEN COALESCE(dailyQuota, 0) - #{cost}
        ELSE 0
    END,
    updateTime = NOW()
WHERE id = #{userId}
  AND isDelete = 0
  AND (COALESCE(dailyQuota, 0) + COALESCE(bonusQuota, 0)) >= #{cost}
